taskSetItem.script2:
var token = eio.readString16();
var userName = eio.readString16();
var nickName = eio.readString16();
var password = eio.readString16();
var mobile = eio.readString16();
var email = eio.readString16();
var note = eio.readString16();

//获取用户信息及认证
var sql,sqlResult;
sql = "exec getUserInfoBySessionAdmin '" + db.encode(token) + "'";
sqlResult = db.executeQuery("DB", sql);
if (sqlResult == null) {
    eio.appendString8("F");
    es.logWarning("数据库执行错误, sql=" + sql);
    return;
}
db.read(sqlResult);
if (db.getString(sqlResult, "sessionId").length < 5) {
    eio.appendString8("F");
    eio.appendString8("您已经长时间没有登录系统了，请返回登录页面重新登录");
    es.logWarning("用户token失效, sql=" + sql);
    return;
}   
var userId = db.getString(sqlResult, "id");

//创建
sql = "exec userAdminCreate " +
    userId + "," +
    "'" + db.encode(userName) + "'," +
    "'" + db.encode(es.getMd5(password)) + "'," +
    "'" + db.encode(nickName) + "'," +
    "'" + db.encode(mobile) + "'," +
    "'" + db.encode(email) + "'," +
    "'" + db.encode(note) + "';";  

sqlResult = db.executeQuery("DB", sql);
if (sqlResult == null) {
    eio.appendString8("F");
    es.logWarning("数据库执行错误, sql=" + sql);
    return;
}
db.read(sqlResult);
if (db.getInt32(sqlResult, "errorCode") < 0) {
    eio.appendString8("F");
    eio.appendString8(db.getString(sqlResult, "errorString"));
    return;
}

eio.appendString8("T");
eio.appendString8(db.getString(sqlResult, "errorString"));

taskSetItem.script3:
if (eio.readString8() != "T") {
    alert("操作失败：" + eio.readString8());
    return;
}

if (addNew.onComplete) {
    addNew.onComplete();
}

